"use strict";(globalThis.webpackChunkgsf_docusaurus_template=globalThis.webpackChunkgsf_docusaurus_template||[]).push([[7106],{8683(e){e.exports=JSON.parse('{"tag":{"label":"persona:solution-architect","permalink":"/tags/persona-solution-architect","allTagsPath":"/tags","count":16,"items":[{"id":"catalog/architecture/system-topology/serverless-model-development","title":"Adopt serverless architecture for AI/ML workload processes","description":"Building an ML model takes significant computing resources that need to be optimized for efficient utilization.","permalink":"/catalog/architecture/system-topology/serverless-model-development"},{"id":"catalog/architecture/system-topology/containerize-your-workload-where-applicable","title":"Containerize your workloads","description":"Description","permalink":"/catalog/architecture/system-topology/containerize-your-workload-where-applicable"},{"id":"catalog/architecture/system-topology/implement-stateless-design","title":"Implement stateless design","description":"Service state refers to the in-memory or on-disk data required by a service to function. State includes the data structures and member variables that the service reads and writes. Depending on how the service is architected, the state might also include files or other resources stored on the disk. Applications that consume large memory or on-disk data require larger VM sizes, especially for cloud computing where you would need larger VM SKUs to support high RAM capacity and multiple data disks.","permalink":"/catalog/architecture/system-topology/implement-stateless-design"},{"id":"catalog/requirements/match-slo","title":"Match your service level objectives to business needs","description":"If service downtimes are acceptable it\'s better to not strive for highest availability but to design the solution according to real business needs. Lower availability guarantees can help reduce energy consumption by using less infrastructure components.","permalink":"/catalog/requirements/match-slo"},{"id":"catalog/development/minimizing-deployed-environments","title":"Minimize the total number of deployed environments","description":"In a given application, there may be a need to utilize multiple environments in the application workflow. Typically, a development environment is used for regular updates, while staging or testing enviroments are used to make sure there are no issues before code reaches a production environment where users may have access. Each added environment has an increasing energy impact, which in turn creates more emissions. As such, it is important to understand the necessity of each enviroment and it\'s environmental impact.","permalink":"/catalog/development/minimizing-deployed-environments"},{"id":"catalog/operations/resource-lifecycle/optimise-storage-resource-utilisation","title":"Optimise storage utilization","description":"It\'s better to maximise storage utilisation so the storage layer is optimised for the task, not only in terms of energy proportionality but also in terms of embodied carbon. Two storage units running at low utilization rates will consume more energy than one running at a high utilization rate. In addition, the unused capacity on the underutilised storage unit could be more efficiently used for another task or process.","permalink":"/catalog/operations/resource-lifecycle/optimise-storage-resource-utilisation"},{"id":"catalog/operations/capacity-management/optimize-avg-cpu-utilization","title":"Optimize average CPU utilization","description":"CPU usage and utilization varies throughout the day, sometimes wildly for different computational requirements. The larger the variance between the average and peak CPU utilization values, the more resources need to be provisioned in stand-by mode to absorb those spikes in traffic.","permalink":"/catalog/operations/capacity-management/optimize-avg-cpu-utilization"},{"id":"catalog/operations/capacity-management/optimize-peak-cpu-utilization","title":"Optimize peak CPU utilization","description":"CPU usage and utilization varies throughout the day, sometimes wildly for different computational requirements. The larger the variance between the average and peak CPU utilization values, the more resources need to be provisioned in stand-by mode to absorb those spikes in traffic.","permalink":"/catalog/operations/capacity-management/optimize-peak-cpu-utilization"},{"id":"catalog/architecture/system-topology/queue-non-urgent-requests","title":"Queue non-urgent processing requests","description":"All systems have periods of peak and low load. From a hardware-efficiency perspective, we are more efficient with hardware if we minimise the impact of request spikes with an implementation that allows an even utilization of components. From an energy-efficiency perspective, we are more efficient with energy if we ensure that idle resources are kept to a minimum.","permalink":"/catalog/architecture/system-topology/queue-non-urgent-requests"},{"id":"catalog/architecture/system-topology/reduce-network-traversal-between-VMs","title":"Reduce network traversal between VMs","description":"Description","permalink":"/catalog/architecture/system-topology/reduce-network-traversal-between-VMs"},{"id":"catalog/architecture/system-topology/energy-efficent-ai-edge","title":"Run AI models at the edge","description":"Data computation for ML workloads and ML inference is a significant contributor to the carbon footprint of the ML application. Also, if the ML model is running on the cloud, the data needs to be transferred and processed on the cloud to the required format that can be used by the ML model for inference.","permalink":"/catalog/architecture/system-topology/energy-efficent-ai-edge"},{"id":"catalog/operations/capacity-management/scale-infrastructure-with-user-load","title":"Scale infrastructure with user load","description":"Demand for resources depends on user load at any given time. However, most applications run without taking this into consideration. As a result,resources are underused and inefficient.","permalink":"/catalog/operations/capacity-management/scale-infrastructure-with-user-load"},{"id":"catalog/operations/capacity-management/scale-kubernetes-workloads-based-on-events","title":"Scale Kubernetes workloads based on relevant demand metrics","description":"By default, Kubernetes scales workloads based on CPU and RAM utilization. In practice, however, it\'s difficult to correlate your application\'s demand drivers with CPU and RAM utilization. Scaling your workload based on relevant demand metrics that drive scaling of your applications, such as HTTP requests, queue length, and cloud alerting events can help reduce resource utilization, and therefore also your carbon emissions.","permalink":"/catalog/operations/capacity-management/scale-kubernetes-workloads-based-on-events"},{"id":"catalog/architecture/system-topology/scale-logical-components-independently","title":"Scale logical components independently","description":"Description","permalink":"/catalog/architecture/system-topology/scale-logical-components-independently"},{"id":"catalog/architecture/system-topology/evaluate-using-a-service-mesh","title":"Use a service mesh only if needed","description":"Description","permalink":"/catalog/architecture/system-topology/evaluate-using-a-service-mesh"},{"id":"catalog/architecture/technology-selection/use-serverless","title":"Use serverless cloud services","description":"Description","permalink":"/catalog/architecture/technology-selection/use-serverless"}],"unlisted":false}}')}}]);